mapper.select:
SELECT * FROM dm_messages
WHERE conv_id = #{convId}

  AND (
    sent_at < (SELECT m.sent_at FROM dm_messages m WHERE m.id = #{beforeId})
    OR (
      sent_at = (SELECT m.sent_at FROM dm_messages m WHERE m.id = #{beforeId})
      AND id < #{beforeId}
    )
  )

ORDER BY sent_at DESC, id DESC
LIMIT #{size}
